import{_ as e,o as d,c as a,ag as r}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"帮助中心","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1780491682000}'),i={name:"guide/index.md"};function l(o,t,h,n,s,c){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="帮助中心" tabindex="-1">帮助中心 <a class="header-anchor" href="#帮助中心" aria-label="Permalink to &quot;帮助中心&quot;">​</a></h1><p>PanSave 是一站式网盘媒体自动化管理平台。你可以把它理解成一个长期运行的自部署控制台：先接好 Telegram、网盘、TMDB、Emby，再让它按你的规则扫描频道、追踪榜单、处理豆瓣片单和检查缺集。</p><p>如果是第一次部署，建议先看 <a href="/guide/getting-started">快速开始</a>，再按自己需要的功能阅读下面的帮助。</p><h2 id="我想做什么" tabindex="-1">我想做什么 <a class="header-anchor" href="#我想做什么" aria-label="Permalink to &quot;我想做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>目标</th><th>功能入口</th><th>推荐阅读</th></tr></thead><tbody><tr><td>先把服务跑起来</td><td>Docker / 系统登录</td><td><a href="/guide/deploy/docker">Docker 部署</a>、<a href="/guide/getting-started">快速开始</a></td></tr><tr><td>配置 Telegram、网盘、Emby</td><td>系统配置</td><td><a href="/guide/help/system-settings">系统配置</a></td></tr><tr><td>扫描频道里的资源</td><td>资源获取 / 频道扫描</td><td><a href="/guide/help/resource-acquisition">资源获取</a></td></tr><tr><td>追踪榜单和自定义条目</td><td>资源获取 / 榜单订阅、TMDB 看板、监控清单</td><td><a href="/guide/help/resource-acquisition">资源获取</a></td></tr><tr><td>用豆瓣片单求片</td><td>资源获取 / 豆瓣求片</td><td><a href="/guide/help/douban-requests">豆瓣求片</a></td></tr><tr><td>检查 Emby 里缺了哪些集</td><td>资源整理 / Emby 缺集扫描</td><td><a href="/guide/help/emby-missing">Emby 缺集扫描</a></td></tr><tr><td>查看任务为什么失败</td><td>系统日志、邮箱配置</td><td><a href="/guide/help/logs-notifications">日志与通知</a>、<a href="/guide/help/faq">常见问题</a></td></tr></tbody></table><h2 id="使用顺序" tabindex="-1">使用顺序 <a class="header-anchor" href="#使用顺序" aria-label="Permalink to &quot;使用顺序&quot;">​</a></h2><ol><li>部署并访问 <code>http://localhost:16868</code>。</li><li>使用默认账号 <code>admin/password</code> 登录，并尽快修改账号或密码。</li><li>填写授权码，授权通过后进入系统。</li><li>配置网盘账号，并在转存策略里指定整理源目录。</li><li>配置 Telegram 账号或公开频道模式，再维护要使用的频道。</li><li>配置 TMDB 和 Emby，启用需要的监控策略。</li><li>按场景使用频道扫描、榜单订阅、豆瓣求片或 Emby 缺集扫描。</li></ol><h2 id="几个常见术语" tabindex="-1">几个常见术语 <a class="header-anchor" href="#几个常见术语" aria-label="Permalink to &quot;几个常见术语&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>简单解释</th></tr></thead><tbody><tr><td>Telegram API 模式</td><td>使用你自己的 Telegram 账号读取已加入频道，适合私有频道或需要登录才能访问的频道。</td></tr><tr><td>公开频道模式</td><td>不登录 Telegram，只读取公开可访问的 <code>t.me</code> 频道网页，适合公开频道。</td></tr><tr><td>TMDB</td><td>影视资料库，用来确认电影、剧集、年份、海报和季集结构。</td></tr><tr><td>Emby</td><td>你的媒体库服务，PanSave 用它确认资源是否已经入库、是否缺集。</td></tr><tr><td>整理源目录</td><td>网盘里接收新资源的目标目录。频道扫描、监控、豆瓣求片转存时都会用到它。</td></tr><tr><td>监控清单</td><td>系统正在跟踪的电影或剧集列表，来自榜单、自定义加入、豆瓣求片镜像或缺集补救。</td></tr></tbody></table>',9)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
